import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.jUmBZPH5.js";const p=JSON.parse('{"title":"Welcome to BITXpay","description":"","frontmatter":{},"headers":[],"relativePath":"get-started/index.md","filePath":"get-started/index.md","lastUpdated":1776236592000}'),n={name:"get-started/index.md"};function i(l,e,s,c,d,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="welcome-to-bitxpay" tabindex="-1">Welcome to BITXpay <a class="header-anchor" href="#welcome-to-bitxpay" aria-label="Permalink to &quot;Welcome to BITXpay&quot;">​</a></h1><p>BITXpay is a cryptocurrency payment gateway. Accept Bitcoin, Ethereum, stablecoins, and 14 other assets with a single API, no node infrastructure, and real-time webhooks.</p><h2 id="why-bitxpay" tabindex="-1">Why BITXpay <a class="header-anchor" href="#why-bitxpay" aria-label="Permalink to &quot;Why BITXpay&quot;">​</a></h2><h3 id="move-money-in-minutes" tabindex="-1">Move money in minutes <a class="header-anchor" href="#move-money-in-minutes" aria-label="Permalink to &quot;Move money in minutes&quot;">​</a></h3><p>Send and receive payments 24/7 — no bank cut-off times, no weekends, no holidays.</p><h3 id="self-custodial-wallet" tabindex="-1">Self-custodial wallet <a class="header-anchor" href="#self-custodial-wallet" aria-label="Permalink to &quot;Self-custodial wallet&quot;">​</a></h3><p>You hold your own keys. No third party controls your funds — full ownership, full security.</p><h3 id="crypto-meets-local-currency" tabindex="-1">Crypto meets local currency <a class="header-anchor" href="#crypto-meets-local-currency" aria-label="Permalink to &quot;Crypto meets local currency&quot;">​</a></h3><p>Convert between crypto and local currencies seamlessly. Pay globally, settle locally.</p><h2 id="how-it-works" tabindex="-1">How it Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it Works&quot;">​</a></h2><ol><li><strong>Create intent</strong>: Amount, currency, recipient</li><li><strong>Show Checkout</strong>: Hosted page or embedded widget</li><li><strong>Funds move</strong>: Crypto and fiat, on-chain in minutes</li><li><strong>Webhook fires</strong>: Payment confirmed with full receipt</li></ol><h2 id="what-you-can-build" tabindex="-1">What you can build <a class="header-anchor" href="#what-you-can-build" aria-label="Permalink to &quot;What you can build&quot;">​</a></h2><h3 id="e-commerce-checkout" tabindex="-1">E-commerce checkout <a class="header-anchor" href="#e-commerce-checkout" aria-label="Permalink to &quot;E-commerce checkout&quot;">​</a></h3><p>Accept crypto and local currency payments on any storefront, embedded or hosted.</p><h3 id="cross-border-payments" tabindex="-1">Cross-border payments <a class="header-anchor" href="#cross-border-payments" aria-label="Permalink to &quot;Cross-border payments&quot;">​</a></h3><p>Send money internationally in minutes. No correspondent banks, no 3-day delays.</p><h3 id="global-payroll" tabindex="-1">Global payroll <a class="header-anchor" href="#global-payroll" aria-label="Permalink to &quot;Global payroll&quot;">​</a></h3><p>Pay contractors and employees worldwide in stablecoins or local currency, instantly.</p><h3 id="multi-currency-invoicing" tabindex="-1">Multi-currency invoicing <a class="header-anchor" href="#multi-currency-invoicing" aria-label="Permalink to &quot;Multi-currency invoicing&quot;">​</a></h3><p>Issue invoices in any currency with real-time rate lock-in and automatic settlement.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/get-started/supported-networks">Supported Networks</a> - Learn about the 16 blockchain networks we support</li><li><a href="/docs/get-started/authentication">Authentication</a> - Secure your API integration</li><li><a href="/docs/get-started/quick-start">Quick Start</a> - Start building in minutes</li><li><a href="/docs/get-started/sdks-libraries">SDKs and Libraries</a> - Use our official SDKs</li></ul>',22)])])}const y=a(n,[["render",i]]);export{p as __pageData,y as default};
